import pandas as pd
import numpy as np
from typing import Dict, Any

def data_quality_report(
    df: pd.DataFrame,
    expected_schema: Dict[str, str] = None
) -> Dict[str, Any]:
    """
    Returns a structured quality report for a DataFrame.
    expected_schema: {'col_name': 'dtype_str', ...}
        e.g. {'user_id': 'int64', 'event_ts': 'datetime64[ns]'}
    """
    report = {}

    # 1. Null counts per column
    null_counts = df.isnull().sum()
    report['null_counts'] = null_counts[null_counts > 0].to_dict()
    report['null_pct'] = (
        (null_counts / len(df) * 100).round(2)
        .to_dict()
    )

    # 2. Outlier counts per numeric column (|z-score| > 3)
    numeric_cols = df.select_dtypes(include=[np.number]).columns
    outlier_counts = {}
    for col in numeric_cols:
        col_data = df[col].dropna()
        if col_data.std() > 0:
            z_scores = (col_data - col_data.mean()) / col_data.std()
            outlier_counts[col] = int((z_scores.abs() > 3).sum())
    report['outlier_counts'] = outlier_counts

    # 3. Duplicate row count
    report['duplicate_rows'] = int(df.duplicated().sum())

    # 4. Schema mismatches
    schema_issues = {}
    if expected_schema:
        for col, expected_dtype in expected_schema.items():
            if col not in df.columns:
                schema_issues[col] = {'issue': 'missing_column'}
            elif str(df[col].dtype) != expected_dtype:
                schema_issues[col] = {
                    'expected': expected_dtype,
                    'actual': str(df[col].dtype)
                }
        extra_cols = set(df.columns) - set(expected_schema.keys())
        if extra_cols:
            schema_issues['__extra_columns__'] = list(extra_cols)
    report['schema_mismatches'] = schema_issues

    return report

# Example
expected = {'user_id': 'int64', 'revenue': 'float64', 'date': 'datetime64[ns]'}
report = data_quality_report(df, expected_schema=expected)
